import { createRouter, createWebHashHistory } from "vue-router";
import store from "../store/index";
const routes = [
    {
        path: "/",
        redirect: "/home"
    },
    {
        path: "/login",
        name: "login",
        component: () => import("../views/Login.vue"),
        meta: {
            title: "登录"
        }
    },
    {
        path: "/",
        component: () => import("../views/Main.vue"),
        children: [
            {
                path: "/home",
                name: "home",
                component: () => import("../views/Home.vue"),
                meta: {
                    title: "首页"
                }
            },
            {
                path: "/note",
                name: "note",
                component: () => import("../views/Note.vue"),
                meta: {
                    title: "笔记"
                }
            },
            {
                path: "/mail",
                name: "mail",
                component: () => import("../views/Mail.vue"),
                meta: {
                    title: "邮件"
                }
            },
            {
                path: "/editor",
                name: "editor",
                component: () => import("../views/Editor.vue"),
                meta: {
                    title: "编辑"
                }
            },
            {
                path: "/personal",
                name: "personal",
                component: () => import("../views/Personal.vue"),
                meta: {
                    title: "个人信息"
                }
            },
            {
                path: "/demo",
                name: "demo",
                component: () => import("../views/Demo.vue"),
                meta: {
                    title: "样例"
                },
                children: [
                    {
                        path: "/demo/",
                        redirect: "/demo/mapboxdemo1"
                    },
                    {
                        path: "/demo/mapboxdemo1",
                        name: "mapboxdemo1",
                        component: () => import("../views/demo/Mapboxdemo1.vue"),
                        meta: {
                            title: "mapbox添加点线面"
                        }
                    },
                    {
                        path: "/demo/mapboxdemo2",
                        name: "mapboxdemo2",
                        component: () => import("../views/demo/Mapboxdemo2.vue"),
                        meta: {
                            title: "mapbox添加3d模型"
                        }
                    },
                    {
                        path: "/demo/mapboxdemo3",
                        name: "mapboxdemo3",
                        component: () => import("../views/demo/Mapboxdemo3.vue"),
                        meta: {
                            title: "手动控制3D模型"
                        }
                    },
                    {
                        path: "/demo/mapboxdemo4",
                        name: "mapboxdemo4",
                        component: () => import("../views/demo/Mapboxdemo4.vue"),
                        meta: {
                            title: "3D模型沿轨迹运动"
                        }
                    },
                    {
                        path: "/demo/svgdemo1",
                        name: "svgdemo1",
                        component: () => import("../views/demo/Svgdemo1.vue"),
                        meta: {
                            title: "沿着svg路径运动"
                        }
                    }
                ]
            }
        ]
    }
];

const router = createRouter({
    history: createWebHashHistory(process.env.BASE_URL),
    routes
});

router.beforeEach((to, from, next) => {
    document.title = to.meta.title;
    store.commit("changeLoadStatus", false);
    if (store.state.userInfo === "null") {
        next("/login");
    } else {
        store.commit("setMenu", to.path);
        next();
    }
});

export default router;
