import axios from "../http"; // 导入http中创建的axios实例

const common = {
    // 上传图片
    uploadImage(params) {
        return axios.post(
            `${process.env.VUE_APP_SERVER_URL}/api/common/uploadImage`,
            params
        );
    },
    // 发送邮件
    sendMail(params) {
        return axios.post(
            `${process.env.VUE_APP_SERVER_URL}/api/common/sendMail`,
            params
        );
    }
};
export default common;
